/* ============================================================
   build-bundle.js
   Reads every file in /data/*.json and writes /data/bundle.js,
   which exposes window.FM_BUNDLE = { site, home, ... }.
   This lets the site work by double-clicking index.html (file://),
   where browsers block fetch() of local JSON.

   Run after editing any JSON:   node build-bundle.js
   ============================================================ */
const fs = require('fs');
const path = require('path');

const dataDir = path.join(__dirname, 'data');
const files = fs.readdirSync(dataDir).filter(f => f.endsWith('.json'));

const bundle = {};
for (const f of files) {
  const key = f.replace('.json', '');
  const raw = fs.readFileSync(path.join(dataDir, f), 'utf8');
  try {
    bundle[key] = JSON.parse(raw);
  } catch (e) {
    console.error('Invalid JSON in ' + f + ': ' + e.message);
    process.exit(1);
  }
}

const out =
  '/* AUTO-GENERATED by build-bundle.js — do not edit by hand.\n' +
  '   Edit the JSON files in /data and re-run: node build-bundle.js */\n' +
  'window.FM_BUNDLE = ' + JSON.stringify(bundle, null, 2) + ';\n';

fs.writeFileSync(path.join(dataDir, 'bundle.js'), out);
console.log('Wrote data/bundle.js from: ' + files.join(', '));
